import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface PropertyDetails {
  address: string;
  cityStateZip: string;
  price: string;
  status: string;
  beds: number;
  baths: number;
  garage: number;
  description: string;
  features: string[];
}

export interface SectionLink {
  label: string;
  href: string;
  isDropdown?: boolean;
  subItems?: SectionLink[];
}

import { PropertyDetails, SectionLink } from './types';

export const PROPERTY_INFO: PropertyDetails = {
  address: "504 E Black Diamond Dr",
  cityStateZip: "Casa Grande, AZ 85122",
  price: "$TBD",
  status: "Coming Soon",
  beds: 4,
  baths: 2,
  garage: 3,
  description: "Experience luxury living in this stunning single-level home located in the desirable Casa Grande area. Featuring a spacious open floor plan, this property boasts 4 bedrooms, 2 bathrooms, and a versatile 3-car garage. Perfect for entertaining or relaxing, the home offers modern finishes and ample natural light throughout.",
  features: [
    "Single Level",
    "Open Floor Plan",
    "Large Master Suite",
    "Modern Kitchen",
    "Landscaped Backyard"
  ]
};

export const NAVIGATION_LINKS: SectionLink[] = [
  { label: "Home", href: "#home" },
  { label: "Details", href: "#details" },
  { label: "Gallery", href: "#gallery" },
  { label: "Map", href: "#map" },
];

export const DROPDOWN_LINKS: SectionLink[] = [
  { label: "HOA Information", href: "#hoa" },
  { label: "Solar Benefits", href: "#solar" },
];

import React, { useState, useEffect } from 'react';
import { NAVIGATION_LINKS, DROPDOWN_LINKS } from '../constants';

const Navbar: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [isDropdownOpen, setIsDropdownOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 100);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const toggleMenu = () => setIsOpen(!isOpen);

  // Toggle dropdown on click for mobile/touch, hover logic handled via CSS group-hover for desktop
  const toggleDropdown = (e: React.MouseEvent) => {
    e.preventDefault();
    setIsDropdownOpen(!isDropdownOpen);
  };

  return (
    <nav className={`sticky top-0 z-50 transition-all duration-300 ${scrolled ? 'shadow-lg' : ''} bg-navy-800 text-white`}>
      <div className="container mx-auto px-4">
        <div className="flex justify-between items-center h-14">

          {/* Mobile Menu Button */}
          <button
            onClick={toggleMenu}
            className="md:hidden p-2 text-white hover:text-gray-300 focus:outline-none"
          >
            <svg className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              {isOpen ? (
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
              ) : (
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h16M4 18h16" />
              )}
            </svg>
          </button>

          {/* Desktop Navigation */}
          <div className="hidden md:flex flex-1 items-center justify-between">
            <div className="flex space-x-1">
              {NAVIGATION_LINKS.map((link) => (
                <a
                  key={link.label}
                  href={link.href}
                  className="px-4 py-2 hover:bg-navy-700 transition-colors text-sm font-medium uppercase tracking-wide"
                >
                  {link.label}
                </a>
              ))}
            </div>

            {/* Desktop More Dropdown */}
            <div className="relative group">
              <button
                className="flex items-center px-4 py-2 hover:bg-navy-700 transition-colors text-sm font-medium uppercase tracking-wide focus:outline-none"
                aria-haspopup="true"
              >
                More
                <svg className="ml-1 h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
                </svg>
              </button>

              <div className="absolute right-0 mt-0 w-48 bg-white rounded-b shadow-xl opacity-0 invisible group-hover:opacity-100 group-hover:visible transition-all duration-200 transform origin-top-right z-50">
                <div className="py-1">
                  {DROPDOWN_LINKS.map((link) => (
                    <a
                      key={link.label}
                      href={link.href}
                      className="block px-4 py-3 text-sm text-gray-700 hover:bg-gray-100 hover:text-navy-800"
                    >
                      {link.label}
                    </a>
                  ))}
                </div>
              </div>
            </div>
          </div>
        </div>

        {/* Mobile Navigation Menu */}
        <div className={`md:hidden overflow-hidden transition-all duration-300 ease-in-out ${isOpen ? 'max-h-screen opacity-100' : 'max-h-0 opacity-0'}`}>
          <div className="flex flex-col pb-4 space-y-1 bg-navy-800 border-t border-navy-700">
            {NAVIGATION_LINKS.map((link) => (
              <a
                key={link.label}
                href={link.href}
                onClick={() => setIsOpen(false)}
                className="block px-4 py-3 hover:bg-navy-700 text-sm font-medium uppercase border-b border-navy-700/50"
              >
                {link.label}
              </a>
            ))}

            {/* Mobile Dropdown */}
            <div>
              <button
                onClick={toggleDropdown}
                className="flex w-full items-center justify-between px-4 py-3 hover:bg-navy-700 text-sm font-medium uppercase focus:outline-none"
              >
                More
                <svg className={`ml-1 h-4 w-4 transform transition-transform ${isDropdownOpen ? 'rotate-180' : ''}`} fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
                </svg>
              </button>

              <div className={`bg-navy-900 transition-all duration-200 ${isDropdownOpen ? 'block' : 'hidden'}`}>
                {DROPDOWN_LINKS.map((link) => (
                  <a
                    key={link.label}
                    href={link.href}
                    onClick={() => setIsOpen(false)}
                    className="block pl-8 pr-4 py-3 text-sm text-gray-300 hover:text-white hover:bg-navy-800"
                  >
                    {link.label}
                  </a>
                ))}
              </div>
            </div>
          </div>
        </div>
      </div>
    </nav>
  );
};

export default Navbar;

