import React from 'react';

const Map: React.FC = () => {
  const addressEncoded = encodeURIComponent("504 E Black Diamond Dr, Casa Grande, AZ 85122");

  return (
    <section id="map" className="py-0 relative h-96 w-full bg-gray-200">
      <iframe
        width="100%"
        height="100%"
        style={{ border: 0 }}
        loading="lazy"
        allowFullScreen
        referrerPolicy="no-referrer-when-downgrade"
        src={`https://www.google.com/maps/embed/v1/place?key=${process.env.API_KEY || ''}&q=${addressEncoded}`}
        className="absolute inset-0 grayscale hover:grayscale-0 transition-all duration-500"
        title="Map Location"
      >
      </iframe>
      {/* Fallback visual if no API key is present in real env, usually iframe works with just query in some embed modes, 
          but for standard embed API we need a key. Using a visual fallback for the 'placeholder' requirement if iframe fails to load or is restricted */}
      <div className="absolute inset-0 pointer-events-none flex items-center justify-center bg-gray-100 -z-10">
        <p className="text-gray-500 font-medium">Map Loading...</p>
      </div>
    </section>
  );
};

