import ComingSoon from './components/ComingSoon';
import { SHOW_COMING_SOON } from './constants';

function App() {
  // Use state to track if the user has triggered the secret bypass
  const [isBypassed, setIsBypassed] = useState(() => {
    if (typeof window !== 'undefined') {
      return sessionStorage.getItem('listing_bypass_active') === 'true';
    }
    return false;
  });

  const handleBypass = () => {
    sessionStorage.setItem('listing_bypass_active', 'true');
    setIsBypassed(true);
  };

  // If the coming soon flag is set in constants.ts AND the secret bypass hasn't been triggered
  if (SHOW_COMING_SOON && !isBypassed) {
    return <ComingSoon onBypass={handleBypass} />;
  }

  return (
    <div className="min-h-screen flex flex-col font-sans">
      <Header />
      <Navbar />
      <main className="flex-grow">
        <Hero />
        <Details />
        <Gallery />
        <Map />
        <HOASection />
        <SolarSection />
      </main>
      <Footer />
    </div>
  );
}

export default App;

