  // Hidden Keyboard Command: Type "unlock" anywhere
  useEffect(() => {
    let buffer = '';
    const handleKeyDown = (e: KeyboardEvent) => {
      buffer += e.key.toLowerCase();
      if (buffer.endsWith('unlock')) {
        onBypass?.();
